#include <stdio.h>
#include <limits.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, Q; scanf("%d %d", &N, &Q);
        int A[15];
        for (int i = 0; i < N; ++i) scanf("%d", &A[i]);
        while (Q--) {
            int L, R; scanf("%d %d", &L, &R);
            int ans = INT_MAX;
            for (int i = L-1; i < R-1; ++i) {
                for (int j = i+1; j < R; ++j) {
                    int x = A[i] ^ A[j];
                    if (x < ans) ans = x;
                }
            }
            printf("%d\n", ans);
        }
    }
    return 0;
}

